PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?end_date WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasProjects ?child ; p:hasConstruction_Companies ?parent . } GROUP BY ?child }
  ?child p:end_date ?end_date .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Construction_Companies } }
  FILTER(?nf = ?total)
}

