ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?end_date WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasProjects ?child ; p:hasConstruction_Companies ?parent . } GROUP BY ?child }
  ?child p:end_date ?end_date .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Construction_Companies } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?company_name ?end_date WHERE {
  ?construction_companies_projects a :Construction_Companies_Projects .
  ?projects a :Projects .
  ?construction_companies_projects p:hasProjects ?projects .
  ?construction_companies a :Construction_Companies .
  ?construction_companies_projects p:hasConstruction_Companies ?construction_companies .
  ?construction_companies p:company_name ?company_name .
  ?projects p:end_date ?end_date .
} }
}

